# frozen_string_literal: true

require 'zlib'
require 'digest/md5'

class Redis
  class HashRing
    POINTS_PER_SERVER = 160 # this is the default in libmemcached

    attr_reader :ring, :sorted_keys, :replicas, :nodes

    # nodes is a list of objects that have a proper to_s representation.
    # replicas indicates how many virtual points should be used pr. node,
    # replicas are required to improve the distribution.
    def initialize(nodes = [], replicas = POINTS_PER_SERVER)
      @replicas = replicas
      @ring = {}
      @nodes = []
      @sorted_keys = []
      nodes.each do |node|
        add_node(node)
      end
    end

    # Adds a `node` to the hash ring (including a number of replicas).
    def add_node(node)
      @nodes << node
      @replicas.times do |i|
        key = server_hash_for("#{node.id}:#{i}")
        @ring[key] = node
        @sorted_keys << key
      end
      @sorted_keys.sort!
    end

    def remove_node(node)
      @nodes.reject! { |n| n.id == node.id }
      @replicas.times do |i|
        key = server_hash_for("#{node.id}:#{i}")
        @ring.delete(key)
        @sorted_keys.reject! { |k| k == key }
      end
    end

    # get the node in the hash ring for this key
    def get_node(key)
      hash = hash_for(key)
      idx = binary_search(@sorted_keys, hash)
      @ring[@sorted_keys[idx]]
    end

    def iter_nodes(key)
      return [nil, nil] if @ring.empty?

      crc = hash_for(key)
      pos = binary_search(@sorted_keys, crc)
      @ring.size.times do |n|
        yield @ring[@sorted_keys[(pos + n) % @ring.size]]
      end
    end

    private

    def hash_for(key)
      Zlib.crc32(key)
    end

    def server_hash_for(key)
      Digest::MD5.digest(key).unpack1("L>")
    end

    # Find the closest index in HashRing with value <= the given value
    def binary_search(ary, value)
      upper = ary.size
      lower = 0

      while lower < upper
        mid = (lower + upper) / 2
        if ary[mid] > value
          upper = mid
        else
          lower = mid + 1
        end
      end

      upper - 1
    end
  end
end

# frozen_string_literal: true

require_relative "liquid_renderer/file"
require_relative "liquid_renderer/table"

module Jekyll
  class LiquidRenderer
    def initialize(site)
      @site = site
      Liquid::Template.error_mode = @site.config["liquid"]["error_mode"].to_sym
      reset
    end

    def reset
      @stats = {}
      @cache = {}
    end

    def file(filename)
      filename = normalize_path(filename)
      LiquidRenderer::File.new(self, filename).tap do
        @stats[filename] ||= new_profile_hash
      end
    end

    def increment_bytes(filename, bytes)
      @stats[filename][:bytes] += bytes
    end

    def increment_time(filename, time)
      @stats[filename][:time] += time
    end

    def increment_count(filename)
      @stats[filename][:count] += 1
    end

    def stats_table(num_of_rows = 50)
      LiquidRenderer::Table.new(@stats).to_s(num_of_rows)
    end

    def self.format_error(error, path)
      "#{error.message} in #{path}"
    end

    # A persistent cache to store and retrieve parsed templates based on the filename
    # via `LiquidRenderer::File#parse`
    #
    # It is emptied when `self.reset` is called.
    def cache
      @cache ||= {}
    end

    private

    def normalize_path(filename)
      @normalize_path ||= {}
      @normalize_path[filename] ||= begin
        theme_dir = @site.theme&.root
        case filename
        when %r!\A(#{Regexp.escape(@site.source)}/)(?<rest>.*)!io
          Regexp.last_match(:rest)
        when %r!(/gems/.*)*/gems/(?<dirname>[^/]+)(?<rest>.*)!,
             %r!(?<dirname>[^/]+/lib)(?<rest>.*)!
          "#{Regexp.last_match(:dirname)}#{Regexp.last_match(:rest)}"
        when theme_dir && %r!\A#{Regexp.escape(theme_dir)}/(?<rest>.*)!io
          PathManager.join(@site.theme.basename, Regexp.last_match(:rest))
        when %r!\A/(.*)!
          Regexp.last_match(1)
        else
          filename
        end
      end
    end

    def new_profile_hash
      Hash.new { |hash, key| hash[key] = 0 }
    end
  end
end
